import React, { useState } from 'react';
import axios from 'axios';

function HireMeForm() {
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    serviceType: 'Web Development',
    paymentMethod: 'UPI'
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:5000/api/hire', formData);
      alert("🚀 Request Sent! I will contact you soon.");
      setFormData({ fullName: '', email: '', serviceType: 'Web Development', paymentMethod: 'UPI' });
    } catch (err) {
      alert("❌ Something went wrong!");
    }
  };

  return (
    <div className="hire-container">
      <style>{`
        @import url('https://fonts.googleapis.com');
        
        .hire-container {
          display: flex;
          justify-content: center;
          align-items: center;
          min-height: 100vh;
          background: #f4f7fa;
          font-family: 'Plus Jakarta Sans', sans-serif;
          padding: 20px;
        }

        .hire-card {
          background: white;
          padding: 40px;
          border-radius: 24px;
          box-shadow: 0 20px 40px rgba(0,0,0,0.05);
          width: 100%;
          max-width: 450px;
          border: 1px solid #f0f0f0;
        }

        .hire-card h2 {
          font-weight: 800;
          color: #1a202c;
          text-align: center;
          font-size: 2rem;
          letter-spacing: -1px;
          margin-bottom: 30px;
        }

        .hire-card h2 span { color: #3182ce; }

        .form-group { margin-bottom: 20px; }

        .form-group label {
          display: block;
          font-size: 0.8rem;
          font-weight: 700;
          color: #718096;
          text-transform: uppercase;
          margin-bottom: 8px;
          letter-spacing: 0.5px;
        }

        .form-group input, .form-group select {
          width: 100%;
          padding: 14px 18px;
          border-radius: 12px;
          border: 2px solid #edf2f7;
          background: #f8fafc;
          font-size: 1rem;
          transition: 0.3s;
          outline: none;
          color: #2d3748;
        }

        .form-group input:focus, .form-group select:focus {
          border-color: #3182ce;
          background: white;
          box-shadow: 0 0 0 4px rgba(49, 130, 206, 0.1);
        }

        .submit-btn {
          width: 100%;
          padding: 16px;
          background: linear-gradient(135deg, #3182ce 0%, #2c5282 100%);
          color: white;
          border: none;
          border-radius: 12px;
          font-weight: 700;
          font-size: 1.1rem;
          cursor: pointer;
          transition: 0.3s;
          box-shadow: 0 10px 20px rgba(49, 130, 206, 0.2);
          margin-top: 10px;
        }

        .submit-btn:hover {
          transform: translateY(-2px);
          box-shadow: 0 15px 30px rgba(49, 130, 206, 0.3);
        }

        .payment-label { color: #e53e3e !important; }
      `}</style>

      <div className="hire-card">
        <h2>Hire <span>Me</span></h2>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Full Name</label>
            <input 
              type="text" 
              placeholder="e.g. Rahul Patil" 
              value={formData.fullName}
              onChange={(e) => setFormData({...formData, fullName: e.target.value})}
              required 
            />
          </div>

          <div className="form-group">
            <label>Email Address</label>
            <input 
              type="email" 
              placeholder="name@example.com" 
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
              required 
            />
          </div>

          <div className="form-group">
            <label>Select Service</label>
            <select 
              value={formData.serviceType}
              onChange={(e) => setFormData({...formData, serviceType: e.target.value})}
            >
              <option value="Web Development">Web Development</option>
              <option value="UI/UX Design">UI/UX Design</option>
              <option value="App Development">App Development</option>
              <option value="SEO Optimization">SEO Optimization</option>
            </select>
          </div>

          <div className="form-group">
            <label className="payment-label">Payment Method</label>
            <select 
              value={formData.paymentMethod}
              onChange={(e) => setFormData({...formData, paymentMethod: e.target.value})}
            >
              <option value="UPI">UPI / QR Code</option>
              <option value="Bank Transfer">Bank Transfer</option>
              <option value="PayPal">PayPal</option>
            </select>
          </div>

          <button type="submit" className="submit-btn">
            Send Work Request
          </button>
        </form>
      </div>
    </div>
  );
}

export default HireMeForm;
